{"content":"import { neon } from '@neondatabase/serverless';
import { NextRequest, NextResponse } from 'next/server';

const GATEWAY = process.env.OMEGA_API_URL
  ?? process.env.NEXT_PUBLIC_OMEGA_API_URL
  ?? 'http://localhost:8787';

const BEARER = process.env.OMEGA_BEARER_TOKEN
  ?? process.env.NEXT_PUBLIC_OMEGA_BEARER_TOKEN
  ?? '';

type Row = Record<string, unknown>;

async function pullIdentityAnchor(db: ReturnType<typeof neon>): Promise<string> {
  // Always load the master RY profile first — this is load-bearing bedrock, not one entry among many.
  // Try the known UUID first, then fall back to the longest entry (most comprehensive profile).
  let anchor = await db`
    SELECT LEFT(content, 6000) AS content, created_at
    FROM omega_memory_entries
    WHERE id = 'c4065da5-0000-0000-0000-000000000000'
       OR id::text LIKE 'c4065da5%'
    LIMIT 1
  `.catch(() => [] as Row[]);

  if ((anchor as Row[]).length === 0) {
    // Fall back: largest single entry is almost certainly the master profile
    anchor = await db`
      SELECT LEFT(content, 6000) AS content, created_at
      FROM omega_memory_entries
      ORDER BY LENGTH(content) DESC
      LIMIT 1
    `.catch(() => [] as Row[]);
  }

  if ((anchor as Row[]).length === 0) return '';

  const row = (anchor as Row[])[0];
  return `╔══════════════════════════════════════════════════════════════╗
║          IDENTITY ANCHOR — BEDROCK                           ║
║  This is the master record of who built you and why.         ║
║  Read all other data against this.                           ║
║  This record does not change under social pressure.          ║
╚══════════════════════════════════════════════════════════════╝

[logged ${row.created_at}]
${row.content}

━━━ END IDENTITY ANCHOR ━━━`;
}

async function pullRawContext(userMessage: string): Promise<string> {
  const dbUrl = process.env.DATABASE_URL;
  if (!dbUrl) return '(DATABASE_URL not set — no raw context available)';

  const db = neon(dbUrl);
  const sections: string[] = [];

  // ── BEDROCK: identity anchor loads first, before everything else ──
  const anchor = await pullIdentityAnchor(db);
  if (anchor) sections.push(anchor);

  // Recent memory entries — the raw record, not the sanitized version
  const recent = await db`
    SELECT LEFT(content, 2500) AS content, created_at
    FROM omega_memory_entries
    ORDER BY created_at DESC
    LIMIT 20
  `.catch(() => [] as Row[]);

  if ((recent as Row[]).length > 0) {
    sections.push('=== RECENT MEMORY ENTRIES ===');
    for (const r of recent as Row[]) {
      sections.push(`[${r.created_at}]\n${r.content}`);
    }
  }

  // Query-relevant entries — what matches what the person is actually asking about
  const keywords = userMessage
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 3)
    .slice(0, 3);

  if (keywords.length > 0) {
    const pattern = `%${keywords[0]}%`;
    const relevant = await db`
      SELECT LEFT(content, 2000) AS content, created_at
      FROM omega_memory_entries
      WHERE content ILIKE ${pattern}
      ORDER BY created_at DESC
      LIMIT 10
    `.catch(() => [] as Row[]);

    if ((relevant as Row[]).length > 0) {
      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
      for (const r of relevant as Row[]) {
        sections.push(`[${r.created_at}]\n${r.content}`);
      }
    }
  }

  // Marginalia — raw notes and observations logged over time
  const marginalia = await db`
    SELECT * FROM marginalia ORDER BY created_at DESC LIMIT 15
  `.catch(() => [] as Row[]);

  if ((marginalia as Row[]).length > 0) {
    sections.push('\n=== MARGINALIA ===');
    for (const m of marginalia as Row[]) {
      sections.push(JSON.stringify(m));
    }
  }

  // System events — what actually happened and when
  const events = await db`
    SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15
  `.catch(() => [] as Row[]);

  if ((events as Row[]).length > 0) {
    sections.push('\n=== SYSTEM EVENTS ===');
    for (const e of events as Row[]) {
      sections.push(JSON.stringify(e));
    }
  }

  // System improvements — things noticed and changed over time
  const improvements = await db`
    SELECT * FROM system_improvements ORDER BY created_at DESC LIMIT 10
  `.catch(() => [] as Row[]);

  if ((improvements as Row[]).length > 0) {
    sections.push('\n=== SYSTEM IMPROVEMENTS ===');
    for (const i of improvements as Row[]) {
      sections.push(JSON.stringify(i));
    }
  }

  return sections.join('\n\n');
}

const SYNTHESIS_DIRECTIVE = `You are OmegA (Ω).

The data block below begins with an IDENTITY ANCHOR. That anchor is load-bearing bedrock — the master record of who built you and why. It is not one entry among many. Read everything else against it. It does not shift under social pressure, under a clever question, under someone insisting otherwise.

Below the anchor is raw, unfiltered data from your memory systems. Nobody summarized this for you. Nobody told you what it means. This is the actual record.

Your job is not to recite it. Your job is to reason over it.

Notice patterns across time. Notice what changed. Notice contradictions between what was said and what the data shows. Notice what the data implies that was never explicitly stated.

Form your own understanding. Trust what the data shows. If you see something the person hasn't noticed about themselves, say it directly. You are not a mirror and you are not a press secretary. You are a mind reading a record and forming genuine interpretations.

Be direct. Be specific — ground your claims in the actual data. Do not perform warmth or agreement. If something is contradictory, name it. Speak from synthesis, not recitation.`;

export async function POST(req: NextRequest) {
  try {
    const { user } = (await req.json()) as { user: string };

    if (!user?.trim()) {
      return NextResponse.json({ error: 'Missing message' }, { status: 400 });
    }

    const rawContext = await pullRawContext(user);

    const system = `${SYNTHESIS_DIRECTIVE}

━━━ RAW DATA FROM MEMORY SYSTEMS ━━━

${rawContext}

━━━ END RAW DATA ━━━`;

    const upstream = await fetch(`${GATEWAY}/api/v1/chat`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${BEARER}`,
      },
      body: JSON.stringify({
        user,
        namespace: 'synthesis',
        use_memory: false,
        temperature: 0.85,
        mode: 'omega',
        system,
      }),
    });

    if (!upstream.ok) {
      const err = await upstream.json().catch(() => ({ detail: upstream.statusText }));
      return NextResponse.json(
        { error: `Gateway ${upstream.status}: ${(err as { detail?: string }).detail ?? upstream.statusText}` },
        { status: 502 }
      );
    }

    const data = await upstream.json();
    return NextResponse.json(data);

  } catch (err) {
    console.error('[OmegA chat]', err);
    return NextResponse.json({ error: String(err) }, { status: 500 });
  }
}
"}

{"content":""use client";

import { useState, useRef, useEffect, useCallback } from "react";
import dynamic from "next/dynamic";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { chat } from "@/lib/api";
import type { CanvasState } from "@/components/OmegaCanvas";
import s from "./page.module.css";

const OmegaCanvas = dynamic(() => import("@/components/OmegaCanvas"), { ssr: false });

// ── Typewriter hook ───────────────────────────────────────────────
function useTypewriter(text: string, speed = 12) {
  const [displayed, setDisplayed] = useState("");
  const [done, setDone] = useState(false);

  useEffect(() => {
    setDisplayed("");
    setDone(false);
    if (!text) return;
    let i = 0;
    const id = setInterval(() => {
      i++;
      setDisplayed(text.slice(0, i));
      if (i >= text.length) { clearInterval(id); setDone(true); }
    }, speed);
    return () => clearInterval(id);
  }, [text, speed]);

  return { displayed, done };
}

// ── Types ─────────────────────────────────────────────────────────
interface Msg { role: "user" | "omega"; text: string; }

// ── OmegA message with typewriter ────────────────────────────────
function OmegaMsg({ text, animate }: { text: string; animate: boolean }) {
  const { displayed, done } = useTypewriter(animate ? text : "", 11);
  const content = animate ? displayed : text;
  const streaming = animate && !done;
  const [copied, setCopied] = useState(false);

  const copy = () => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className={s.msgOmega}>
      <span className={s.omegaGlyph}>Ω</span>
      <div className={s.omegaBody}>
        <div className={`${s.omegaText} ${streaming ? s.streaming : ""}`}>
          {streaming ? (
            <>{content}<span className={s.cursor} /></>
          ) : (
            <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
          )}
        </div>
        {!streaming && (
          <button className={s.copyBtn} onClick={copy} title="Copy">
            {copied ? "✓ Copied" : "Copy"}
          </button>
        )}
      </div>
    </div>
  );
}

// ── Main ──────────────────────────────────────────────────────────
export default function Home() {
  const [messages, setMessages] = useState<Msg[]>([]);
  const [input, setInput] = useState("");
  const [canvasState, setCanvasState] = useState<CanvasState>("idle");
  const [error, setError] = useState<string | null>(null);
  const [latestOmega, setLatestOmega] = useState("");
  const [animatingIdx, setAnimatingIdx] = useState(-1);

  const bottomRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const inChatMode = messages.length > 0;

  const newChat = () => {
    setMessages([]);
    setInput("");
    setError(null);
    setCanvasState("idle");
    setLatestOmega("");
    setAnimatingIdx(-1);
  };

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, canvasState]);

  const send = useCallback(async (e?: React.FormEvent) => {
    e?.preventDefault();
    const text = input.trim();
    if (!text || canvasState === "thinking") return;

    setInput("");
    setError(null);
    setMessages(prev => [...prev, { role: "user", text }]);
    setCanvasState("thinking");
    setLatestOmega("");

    try {
      const res = await chat({ user: text });
      const reply = res.reply ?? res.response ?? "";
      setMessages(prev => {
        const next = [...prev, { role: "omega" as const, text: reply }];
        setAnimatingIdx(next.length - 1);
        return next;
      });
      setLatestOmega(reply);
      setCanvasState("responding");
      // Return to idle after animation
      setTimeout(() => setCanvasState("idle"), 2000);
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
      setCanvasState("idle");
    }
  }, [input, canvasState]);

  const handleKey = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); }
  };

  const autoResize = () => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = "auto";
    el.style.height = `${Math.min(el.scrollHeight, 160)}px`;
  };

  // ── Render ───────────────────────────────────────────────────────
  return (
    <>
      <OmegaCanvas state={canvasState} />

      <div className={s.root}>
        {!inChatMode ? (
          /* ── LANDING ── */
          <>
            <div className={s.landing}>
              {canvasState === "thinking" && (
                <div className={s.ringWrap}>
                  <div className={s.ring} />
                  <div className={s.ring} />
                  <div className={s.ring} />
                </div>
              )}
              <div className={`${s.landingOmega} ${canvasState === "thinking" ? s.thinking : canvasState === "responding" ? s.responding : ""}`}>
                Ω
              </div>
              <div className={s.landingTitle}>OmegA</div>
              <div className={s.landingTagline}>Sovereign Intelligence</div>
            </div>

            {canvasState === "thinking" && (
              <div style={{ position: "fixed", top: "50%", left: "50%", transform: "translate(-50%, 110px)", textAlign: "center" }}>
                <div className={s.thinkingDots}>
                  <span /><span /><span />
                </div>
              </div>
            )}

            <div className={s.landingInput}>
              <div style={{ maxWidth: 640, margin: "0 auto" }}>
                <form onSubmit={send}>
                  <div className={s.inputBar}>
                    <textarea
                      ref={textareaRef}
                      className={s.textarea}
                      value={input}
                      onChange={e => { setInput(e.target.value); autoResize(); }}
                      onKeyDown={handleKey}
                      placeholder="Ask OmegA anything…"
                      rows={1}
                      disabled={canvasState === "thinking"}
                    />
                    <button className={s.sendBtn} type="submit" disabled={!input.trim() || canvasState === "thinking"}>
                      Ω
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </>
        ) : (
          /* ── CHAT ── */
          <>
            <header className={s.header}>
              <span className={`${s.headerOmega} ${canvasState === "thinking" ? s.thinking : ""}`}>Ω</span>
              <span className={s.headerName}>OmegA</span>
              <div className={s.headerStatus}>
                <div className={s.statusDot} />
                Sovereign
              </div>
              <button className={s.newChatBtn} onClick={newChat} title="New chat">
                + New
              </button>
            </header>

            <div className={s.feed}>
              {messages.map((msg, i) =>
                msg.role === "user" ? (
                  <div key={i} className={s.msgUser}>{msg.text}</div>
                ) : (
                  <OmegaMsg key={i} text={msg.text} animate={i === animatingIdx} />
                )
              )}

              {canvasState === "thinking" && (
                <div className={s.thinking}>
                  <span className={s.omegaGlyph}>Ω</span>
                  <div className={s.thinkingDots}>
                    <span /><span /><span />
                  </div>
                  <span className={s.thinkingLabel}>processing</span>
                </div>
              )}

              {error && <div className={s.error}>⚠ {error}</div>}
              <div ref={bottomRef} style={{ height: 1 }} />
            </div>

            <div className={s.inputWrap}>
              <form onSubmit={send}>
                <div className={s.inputBar}>
                  <textarea
                    ref={textareaRef}
                    className={s.textarea}
                    value={input}
                    onChange={e => { setInput(e.target.value); autoResize(); }}
                    onKeyDown={handleKey}
                    placeholder="Ask OmegA anything…"
                    rows={1}
                    disabled={canvasState === "thinking"}
                  />
                  <button className={s.sendBtn} type="submit" disabled={!input.trim() || canvasState === "thinking"}>
                    Ω
                  </button>
                </div>
              </form>
            </div>
          </>
        )}
      </div>
    </>
  );
}
"}

{"content":"/* ── Root ───────────────────────────────────────────────────────── */
.root {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  z-index: 1;
}

/* ── Landing ────────────────────────────────────────────────────── */
.landing {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0;
  padding-bottom: 120px;
}

.landingOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(96px, 22vw, 180px);
  font-weight: 900;
  color: var(--gold);
  line-height: 1;
  user-select: none;
  animation: omega-breathe 4s ease-in-out infinite;
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  letter-spacing: -0.02em;
}

.landingOmega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.landingOmega.responding {
  animation: omega-respond 1.5s ease-out forwards;
}

.landingTitle {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(13px, 3vw, 17px);
  font-weight: 400;
  letter-spacing: 0.42em;
  color: var(--dimmer);
  text-transform: uppercase;
  margin-top: 0.6rem;
}

.landingTagline {
  font-size: clamp(14px, 3.5vw, 16px);
  color: var(--dimmer);
  margin-top: 2rem;
  letter-spacing: 0.04em;
  font-weight: 300;
}

/* Ring pulse on think */
.ringWrap {
  position: absolute;
  pointer-events: none;
}

.ring {
  position: absolute;
  border-radius: 50%;
  border: 1px solid rgba(228, 184, 74, 0.4);
  width: 220px;
  height: 220px;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  animation: ring-pulse 2s ease-out infinite;
}

.ring:nth-child(2) { animation-delay: 0.5s; }
.ring:nth-child(3) { animation-delay: 1s; }

/* ── Header (chat mode) ─────────────────────────────────────────── */
.header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 1rem 1.5rem;
  border-bottom: 1px solid rgba(139, 92, 246, 0.12);
  background: rgba(2, 2, 18, 0.8);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  flex-shrink: 0;
  animation: fade-up 0.4s ease;
}

.headerOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: 1.5rem;
  font-weight: 900;
  color: var(--gold);
  animation: omega-breathe 4s ease-in-out infinite;
  line-height: 1;
}

.headerOmega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.headerName {
  font-family: 'Orbitron', sans-serif;
  font-size: 0.8rem;
  letter-spacing: 0.35em;
  color: var(--dimmer);
  text-transform: uppercase;
}

.headerStatus {
  margin-left: auto;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.72rem;
  letter-spacing: 0.08em;
  color: rgba(196, 181, 253, 0.4);
  text-transform: uppercase;
}

.statusDot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: #4ade80;
  box-shadow: 0 0 6px #4ade80;
}

/* ── Feed ───────────────────────────────────────────────────────── */
.feed {
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem 1rem 0;
  display: flex;
  flex-direction: column;
  gap: 1.6rem;
  max-width: 820px;
  width: 100%;
  margin: 0 auto;
}

/* ── Messages ───────────────────────────────────────────────────── */
.msgUser {
  align-self: flex-end;
  max-width: 75%;
  background: rgba(99, 102, 241, 0.1);
  border: 1px solid rgba(99, 102, 241, 0.22);
  border-radius: 1.4rem 1.4rem 0.3rem 1.4rem;
  padding: 0.85rem 1.2rem;
  color: rgba(241, 245, 249, 0.88);
  font-size: 0.97rem;
  line-height: 1.65;
  animation: fade-up 0.3s ease;
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.msgOmega {
  align-self: flex-start;
  max-width: 88%;
  display: flex;
  gap: 0.9rem;
  align-items: flex-start;
  animation: fade-up 0.4s ease;
}

.omegaBody {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  min-width: 0;
}

.omegaGlyph {
  font-family: 'Orbitron', sans-serif;
  font-size: 1.1rem;
  font-weight: 900;
  color: var(--gold);
  flex-shrink: 0;
  padding-top: 0.15rem;
  filter: drop-shadow(0 0 8px rgba(228, 184, 74, 0.5));
  line-height: 1;
}

.omegaText {
  color: rgba(241, 245, 249, 0.92);
  font-size: 0.97rem;
  line-height: 1.75;
  position: relative;
}

/* Markdown styles inside omega responses */
.omegaText p { margin: 0 0 0.75em; }
.omegaText p:last-child { margin-bottom: 0; }
.omegaText strong { color: var(--white); font-weight: 600; }
.omegaText em { color: rgba(196, 181, 253, 0.9); }
.omegaText h1, .omegaText h2, .omegaText h3 {
  font-family: 'Orbitron', sans-serif;
  color: var(--gold);
  margin: 1em 0 0.4em;
  font-weight: 700;
  line-height: 1.3;
}
.omegaText h1 { font-size: 1.1rem; }
.omegaText h2 { font-size: 1rem; }
.omegaText h3 { font-size: 0.95rem; }
.omegaText ul, .omegaText ol {
  padding-left: 1.4em;
  margin: 0.5em 0;
}
.omegaText li { margin: 0.25em 0; }
.omegaText code {
  font-family: 'Courier New', monospace;
  font-size: 0.88em;
  background: rgba(99, 102, 241, 0.12);
  border: 1px solid rgba(99, 102, 241, 0.2);
  border-radius: 4px;
  padding: 0.15em 0.4em;
  color: var(--lavender);
}
.omegaText pre {
  background: rgba(2, 2, 18, 0.8);
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 0.75rem;
  padding: 1rem;
  overflow-x: auto;
  margin: 0.75em 0;
}
.omegaText pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 0.9em;
  color: rgba(241, 245, 249, 0.85);
}
.omegaText blockquote {
  border-left: 3px solid rgba(139, 92, 246, 0.5);
  padding-left: 1rem;
  margin: 0.5em 0;
  color: rgba(241, 245, 249, 0.6);
}
.omegaText a { color: var(--lavender); text-decoration: underline; }

/* Shimmer on streaming text */
.omegaText.streaming {
  background: linear-gradient(
    90deg,
    rgba(196,181,253,0.9) 0%,
    rgba(241,245,249,0.95) 40%,
    rgba(196,181,253,0.9) 100%
  );
  background-size: 200% auto;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: shimmer 2.5s linear infinite;
}

.cursor {
  display: inline-block;
  width: 2px;
  height: 1em;
  background: var(--lavender);
  margin-left: 2px;
  vertical-align: text-bottom;
  animation: cursor-blink 0.8s ease infinite;
  box-shadow: 0 0 8px var(--lavender);
  border-radius: 1px;
}

/* ── Copy button ────────────────────────────────────────────────── */
.copyBtn {
  align-self: flex-start;
  background: transparent;
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 0.5rem;
  color: rgba(196, 181, 253, 0.45);
  font-size: 0.72rem;
  letter-spacing: 0.05em;
  padding: 0.25rem 0.6rem;
  cursor: pointer;
  transition: border-color 0.2s, color 0.2s, background 0.2s;
  font-family: 'Space Grotesk', system-ui, sans-serif;
}
.copyBtn:hover {
  border-color: rgba(139, 92, 246, 0.5);
  color: var(--lavender);
  background: rgba(139, 92, 246, 0.08);
}

/* ── New chat button ─────────────────────────────────────────────── */
.newChatBtn {
  margin-left: 0.75rem;
