     1→import { neon, NeonQueryFunction } from '@neondatabase/serverless';
     2→import { NextRequest, NextResponse } from 'next/server';
     3→
     4→const GATEWAY = process.env.OMEGA_API_URL
     5→  ?? process.env.NEXT_PUBLIC_OMEGA_API_URL
     6→  ?? 'http://localhost:8787';
     7→
     8→const BEARER = process.env.OMEGA_BEARER_TOKEN
     9→  ?? process.env.NEXT_PUBLIC_OMEGA_BEARER_TOKEN
    10→  ?? '';
    11→
    12→/** Timeout for gateway fetch (ms) */
    13→const GATEWAY_TIMEOUT_MS = 15_000;
    14→
    15→/** Number of retries on gateway timeout before surfacing error */
    16→const GATEWAY_RETRIES = 1;
    17→
    18→type Row = Record<string, unknown>;
    19→
    20→async function pullIdentityAnchor(db: NeonQueryFunction<false, false>): Promise<string> {
    21→  // Always load the master RY profile first — this is load-bearing bedrock, not one entry among many.
    22→  // Try the known UUID first, then fall back to the longest entry (most comprehensive profile).
    23→  let anchor = await db`
    24→    SELECT LEFT(content, 6000) AS content, created_at
    25→    FROM omega_memory_entries
    26→    WHERE id = 'c4065da5-0000-0000-0000-000000000000'
    27→       OR id::text LIKE 'c4065da5%'
    28→    LIMIT 1
    29→  `.catch(() => [] as Row[]);
    30→
    31→  if ((anchor as Row[]).length === 0) {
    32→    // Fall back: largest single entry is almost certainly the master profile
    33→    anchor = await db`
    34→      SELECT LEFT(content, 6000) AS content, created_at
    35→      FROM omega_memory_entries
    36→      ORDER BY LENGTH(content) DESC
    37→      LIMIT 1
    38→    `.catch(() => [] as Row[]);
