/* ── Root ───────────────────────────────────────────────────────── */
.root {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  z-index: 1;
}

/* ── Landing ────────────────────────────────────────────────────── */
.landing {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0;
  padding-bottom: 120px;
}

.landingOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(96px, 22vw, 180px);
  font-weight: 900;
  color: var(--gold);
  line-height: 1;
  user-select: none;
  animation: omega-breathe 4s ease-in-out infinite;
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  letter-spacing: -0.02em;
  will-change: filter, transform;
}

.landingOmega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.landingOmega.responding {
  animation: omega-respond 1.5s ease-out forwards;
}

.landingTitle {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(13px, 3vw, 17px);
  font-weight: 400;
  letter-spacing: 0.42em;
  color: var(--dimmer);
  text-transform: uppercase;
  margin-top: 0.6rem;
}

.landingTagline {
  font-size: clamp(14px, 3.5vw, 16px);
  color: var(--dimmer);
  margin-top: 2rem;
  letter-spacing: 0.04em;
  font-weight: 300;
}

/* Ring pulse on think */
.ringWrap {
  position: absolute;
  pointer-events: none;
  will-change: transform, opacity;
}

.ring {
  position: absolute;
  border-radius: 50%;
  border: 1px solid rgba(228, 184, 74, 0.4);
  width: 220px;
  height: 220px;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  animation: ring-pulse 2s ease-out infinite;
  will-change: transform, opacity;
}

.ring:nth-child(2) { animation-delay: 0.5s; }
.ring:nth-child(3) { animation-delay: 1s; }

/* ── Header (chat mode) ─────────────────────────────────────────── */
.header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 1rem 1.5rem;
  border-bottom: 1px solid rgba(139, 92, 246, 0.12);
  background: rgba(2, 2, 18, 0.8);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  flex-shrink: 0;
  animation: fade-up 0.4s ease;
}

.headerOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: 1.5rem;
  font-weight: 900;
  color: var(--gold);
  animation: omega-breathe 4s ease-in-out infinite;
  line-height: 1;
  will-change: filter;
}

.headerOmega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.headerName {
  font-family: 'Orbitron', sans-serif;
  font-size: 0.8rem;
  letter-spacing: 0.35em;
  color: var(--dimmer);
  text-transform: uppercase;
}

.headerStatus {
  margin-left: auto;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.72rem;
  letter-spacing: 0.08em;
  color: rgba(196, 181, 253, 0.4);
  text-transform: uppercase;
}

.statusDot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: #4ade80;
  box-shadow: 0 0 6px #4ade80;
}

/* ── Feed ───────────────────────────────────────────────────────── */
.feed {
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem 1rem 0;
  display: flex;
  flex-direction: column;
  gap: 1.6rem;
  max-width: 820px;
  width: 100%;
  margin: 0 auto;
}

/* ── Messages ───────────────────────────────────────────────────── */
.msgUser {
  align-self: flex-end;
  max-width: 75%;
  background: rgba(99, 102, 241, 0.1);
  border: 1px solid rgba(99, 102, 241, 0.22);
  border-radius: 1.4rem 1.4rem 0.3rem 1.4rem;
  padding: 0.85rem 1.2rem;
  color: rgba(241, 245, 249, 0.88);
  font-size: 0.97rem;
  line-height: 1.65;
  animation: fade-up 0.3s ease;
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.msgOmega {
  align-self: flex-start;
  max-width: 88%;
  display: flex;
  gap: 0.9rem;
  align-items: flex-start;
  animation: fade-up 0.4s ease;
}

.omegaBody {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  min-width: 0;
}

.omegaGlyph {
  font-family: 'Orbitron', sans-serif;
  font-size: 1.1rem;
  font-weight: 900;
  color: var(--gold);
  flex-shrink: 0;
  padding-top: 0.15rem;
  filter: drop-shadow(0 0 8px rgba(228, 184, 74, 0.5));
  line-height: 1;
}

.omegaText {
  color: rgba(241, 245, 249, 0.92);
  font-size: 0.97rem;
  line-height: 1.75;
  position: relative;
}

/* Markdown styles inside omega responses */
.omegaText p { margin: 0 0 0.75em; }
.omegaText p:last-child { margin-bottom: 0; }
.omegaText strong { color: var(--white); font-weight: 600; }
.omegaText em { color: rgba(196, 181, 253, 0.9); }
.omegaText h1, .omegaText h2, .omegaText h3 {
  font-family: 'Orbitron', sans-serif;
  color: var(--gold);
  margin: 1em 0 0.4em;
  font-weight: 700;
  line-height: 1.3;
}
.omegaText h1 { font-size: 1.1rem; }
.omegaText h2 { font-size: 1rem; }
.omegaText h3 { font-size: 0.95rem; }
.omegaText ul, .omegaText ol {
  padding-left: 1.4em;
  margin: 0.5em 0;
}
.omegaText li { margin: 0.25em 0; }
.omegaText code {
  font-family: 'Courier New', monospace;
  font-size: 0.88em;
  background: rgba(99, 102, 241, 0.12);
  border: 1px solid rgba(99, 102, 241, 0.2);
  border-radius: 4px;
  padding: 0.15em 0.4em;
  color: var(--lavender);
}
.omegaText pre {
  background: rgba(2, 2, 18, 0.8);
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 0.75rem;
  padding: 1rem;
  overflow-x: auto;
  margin: 0.75em 0;
}
.omegaText pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 0.9em;
  color: rgba(241, 245, 249, 0.85);
}
.omegaText blockquote {
  border-left: 3px solid rgba(139, 92, 246, 0.5);
  padding-left: 1rem;
  margin: 0.5em 0;
  color: rgba(241, 245, 249, 0.6);
}
.omegaText a { color: var(--lavender); text-decoration: underline; }

/* Shimmer on streaming text */
.omegaText.streaming {
  background: linear-gradient(
    90deg,
    rgba(196,181,253,0.9) 0%,
    rgba(241,245,249,0.95) 40%,
    rgba(196,181,253,0.9) 100%
  );
  background-size: 200% auto;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: shimmer 2.5s linear infinite;
  will-change: background-position;
}

.cursor {
  display: inline-block;
  width: 2px;
  height: 1em;
  background: var(--lavender);
  margin-left: 2px;
  vertical-align: text-bottom;
  animation: cursor-blink 0.8s ease infinite;
  box-shadow: 0 0 8px var(--lavender);
  border-radius: 1px;
}

/* ── Copy button ────────────────────────────────────────────────── */
.copyBtn {
  align-self: flex-start;
  background: transparent;
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 0.5rem;
  color: rgba(196, 181, 253, 0.45);
  font-size: 0.72rem;
  letter-spacing: 0.05em;
  padding: 0.25rem 0.6rem;
  cursor: pointer;
  transition: border-color 0.2s, color 0.2s, background 0.2s;
  font-family: 'Space Grotesk', system-ui, sans-serif;
}
.copyBtn:hover {
  border-color: rgba(139, 92, 246, 0.5);
  color: var(--lavender);
  background: rgba(139, 92, 246, 0.08);
}
.copyBtn:focus-visible {
  outline: 2px solid var(--lavender);
  outline-offset: 2px;
}

/* ── New chat button ─────────────────────────────────────────────── */
.newChatBtn {
  margin-left: 0.75rem;
  background: transparent;
  border: 1px solid rgba(139, 92, 246, 0.25);
  border-radius: 0.6rem;
  color: rgba(196, 181, 253, 0.5);
  font-size: 0.75rem;
  letter-spacing: 0.06em;
  padding: 0.3rem 0.75rem;
  cursor: pointer;
  transition: border-color 0.2s, color 0.2s, background 0.2s;
  font-family: 'Space Grotesk', system-ui, sans-serif;
  flex-shrink: 0;
}
.newChatBtn:hover {
  border-color: rgba(139, 92, 246, 0.6);
  color: var(--lavender);
  background: rgba(139, 92, 246, 0.08);
}
.newChatBtn:focus-visible {
  outline: 2px solid var(--lavender);
  outline-offset: 2px;
}

/* ── Thinking indicator (chat feed) ────────────────────────────── */
.thinkingIndicator {
  align-self: flex-start;
  display: flex;
  align-items: center;
  gap: 0.9rem;
  animation: fade-up 0.3s ease;
  padding: 0.2rem 0;
}

.thinkingDots {
  display: flex;
  gap: 5px;
  align-items: center;
}

.thinkingDots span {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: var(--violet);
  box-shadow: 0 0 6px var(--violet);
  animation: dot-bounce 1.4s ease infinite;
}

.thinkingDots span:nth-child(2) { animation-delay: 0.15s; }
.thinkingDots span:nth-child(3) { animation-delay: 0.3s; }

.thinkingLabel {
  font-size: 0.78rem;
  color: rgba(196, 181, 253, 0.4);
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

/* ── Error ──────────────────────────────────────────────────────── */
.error {
  align-self: center;
  color: rgba(252, 129, 129, 0.8);
  font-size: 0.85rem;
  background: rgba(252, 129, 129, 0.06);
  border: 1px solid rgba(252, 129, 129, 0.15);
  border-radius: 0.75rem;
  padding: 0.6rem 1rem;
  max-width: 400px;
  text-align: center;
}

/* ── Input ──────────────────────────────────────────────────────── */
.inputWrap {
  padding: 1rem 1rem 1.5rem;
  flex-shrink: 0;
  max-width: 820px;
  width: 100%;
  margin: 0 auto;
}

.inputBar {
  display: flex;
  align-items: flex-end;
  gap: 0.6rem;
  background: rgba(8, 8, 28, 0.75);
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 1.4rem;
  padding: 0.6rem 0.6rem 0.6rem 1.2rem;
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  transition: border-color 0.25s, box-shadow 0.25s;
}

.inputBar:focus-within {
  border-color: rgba(139, 92, 246, 0.5);
  box-shadow: 0 0 0 3px rgba(139, 92, 246, 0.08), 0 0 30px rgba(99, 102, 241, 0.12);
}

.textarea {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  color: var(--white);
  font-family: 'Space Grotesk', system-ui, sans-serif;
  /* >= 16px prevents iOS auto-zoom on focus */
  font-size: 16px;
  line-height: 1.55;
  resize: none;
  max-height: 160px;
  overflow-y: auto;
  padding: 0.3rem 0;
}

.textarea::placeholder {
  color: rgba(196, 181, 253, 0.22);
  font-weight: 300;
}

.sendBtn {
  width: 2.8rem;
  height: 2.8rem;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--indigo), var(--violet));
  border: none;
  cursor: pointer;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: 'Orbitron', sans-serif;
  font-size: 1rem;
  font-weight: 700;
  color: rgba(255, 255, 255, 0.9);
  transition: transform 0.2s, box-shadow 0.2s, opacity 0.2s;
  box-shadow: 0 0 16px rgba(99, 102, 241, 0.35);
}

.sendBtn:hover:not(:disabled) {
  transform: scale(1.08) translateY(-1px);
  box-shadow: 0 0 28px rgba(139, 92, 246, 0.6);
}

.sendBtn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
  box-shadow: none;
}

.sendBtn:focus-visible {
  outline: 2px solid var(--lavender);
  outline-offset: 2px;
}

/* ── Landing input overlay ──────────────────────────────────────── */
.landingInput {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 1rem 1rem 1.5rem;
  background: linear-gradient(to top, rgba(2,2,12,0.95) 60%, transparent);
}

/* ── Mobile breakpoints ─────────────────────────────────────────── */
@media (max-width: 480px) {
  .header {
    padding: 0.75rem 1rem;
    gap: 0.5rem;
  }

  .headerName {
    font-size: 0.7rem;
    letter-spacing: 0.25em;
  }

  .headerStatus {
    font-size: 0.65rem;
  }

  .newChatBtn {
    font-size: 0.68rem;
    padding: 0.25rem 0.55rem;
  }

  .feed {
    padding: 1rem 0.75rem 0;
    gap: 1.2rem;
  }

  .msgUser {
    max-width: 85%;
    padding: 0.7rem 1rem;
    font-size: 0.93rem;
    border-radius: 1.2rem 1.2rem 0.2rem 1.2rem;
  }

  .msgOmega {
    max-width: 95%;
    gap: 0.6rem;
  }

  .omegaText {
    font-size: 0.93rem;
  }

  .inputWrap {
    padding: 0.75rem 0.75rem 1rem;
  }

  .inputBar {
    padding: 0.5rem 0.5rem 0.5rem 1rem;
    border-radius: 1.2rem;
  }

  .sendBtn {
    width: 2.4rem;
    height: 2.4rem;
    font-size: 0.9rem;
  }

  .landingInput {
    padding: 0.75rem 0.75rem 1rem;
  }

  .landing {
    padding-bottom: 100px;
  }
}

@media (max-width: 360px) {
  .landingOmega {
    font-size: clamp(72px, 20vw, 96px);
  }

  .headerOmega {
    font-size: 1.2rem;
  }

  .headerStatus {
    display: none;
  }
}

/* ── Reduced motion ─────────────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .landingOmega,
  .headerOmega,
  .ring,
  .cursor,
  .thinkingDots span,
  .omegaText.streaming,
  .msgUser,
  .msgOmega,
  .thinkingIndicator,
  .header {
    animation: none !important;
  }

  .landingOmega,
  .landingOmega.thinking,
  .landingOmega.responding,
  .headerOmega.thinking {
    animation: none !important;
  }

  .ringWrap {
    display: none;
  }
}

